719:     CompletableFuture<AlterShareGroupOffsetsResponseData> persisterInitialize(
720:         InitializeShareGroupStateParameters request,
721:         AlterShareGroupOffsetsResponseData response
722:     ) {
723:         if (request.groupTopicPartitionData().topicsData().isEmpty()) {
724:             return CompletableFuture.completedFuture(response);
