743:     private AlterShareGroupOffsetsResponseData buildErrorResponse(AlterShareGroupOffsetsResponseData response, InitializeShareGroupStateResult result) {
744:         AlterShareGroupOffsetsResponseData data = new AlterShareGroupOffsetsResponseData();
745:         Map<Uuid, Map<Integer, PartitionErrorData>> topicPartitionErrorsMap = result.getErrors();
746:         data.setResponses(
747:             new AlterShareGroupOffsetsResponseData.AlterShareGroupOffsetsResponseTopicCollection(response.responses().stream()
748:                 .map(topic -> {
749:                     AlterShareGroupOffsetsResponseData.AlterShareGroupOffsetsResponseTopic topicData = new AlterShareGroupOffsetsResponseData.AlterShareGroupOffsetsResponseTopic()
750:                         .setTopicName(topic.topicName())
751:                         .setTopicId(topic.topicId());
752:                     topic.partitions().forEach(partition -> {
753:                         if (partition.errorCode() != Errors.NONE.code()) {
754:                             topicData.partitions().add(partition);
755:                             return;
756:                         }
757:                         AlterShareGroupOffsetsResponseData.AlterShareGroupOffsetsResponsePartition partitionData;
758:                         Map<Integer, PartitionErrorData> partitionErrors =
759:                             Optional.ofNullable(topicPartitionErrorsMap)
760:                                 .map(map -> map.get(topic.topicId()))
761:                                 .orElse(Collections.emptyMap());
762:                         PartitionErrorData error = partitionErrors.get(partition.partitionIndex());
763:                         if (error == null) {
764:                             partitionData = partition.duplicate();
765:                         } else {
766:                             partitionData = new AlterShareGroupOffsetsResponseData.AlterShareGroupOffsetsResponsePartition()
767:                                 .setPartitionIndex(partition.partitionIndex())
768:                                 .setErrorCode(error.errorCode())
769:                                 .setErrorMessage(error.errorMessage());
770:                         }
771:                         topicData.partitions().add(partitionData);
772:                     });
773:                     return topicData;
774:                 })
775:                 .iterator()));
776:         return data;
777:     }
