31:     @Test
32:     public void testIsOffsetExpired() {
33:         long currentTimestamp = 1500L;
34:         long commitTimestamp = 500L;
35:         OptionalLong expireTimestampMs = OptionalLong.of(1500);
36:         long offsetsRetentionMs = 500L;
37: 
38:         OffsetExpirationConditionImpl condition = new OffsetExpirationConditionImpl(__ -> commitTimestamp);
39:         OffsetAndMetadata offsetAndMetadata = new OffsetAndMetadata(
40:             100,
41:             OptionalInt.of(1),
42:             "metadata",
43:             commitTimestamp,
44:             expireTimestampMs,
45:             Uuid.ZERO_UUID
46:         );
47: 
48:         // Test when expire timestamp exists (older versions with per partition retention)
49:         // 1. Current timestamp >= expire timestamp => should expire
50:         assertTrue(condition.isOffsetExpired(offsetAndMetadata, currentTimestamp, offsetsRetentionMs));
51: 
52:         // 2. Current timestamp < expire timestamp => should not expire
53:         currentTimestamp = 499;
54:         assertFalse(condition.isOffsetExpired(offsetAndMetadata, currentTimestamp, offsetsRetentionMs));
55: 
56:         // Test when expire timestamp does not exist (current version with no per partition retention)
57:         offsetAndMetadata = new OffsetAndMetadata(
58:             100,
59:             OptionalInt.of(1),
60:             "metadata",
61:             commitTimestamp,
62:             OptionalLong.empty(),
63:             Uuid.ZERO_UUID
64:         );
65: 
66:         // 3. Current timestamp - base timestamp >= offsets retention => should expire
67:         currentTimestamp = 1000L;
68:         assertTrue(condition.isOffsetExpired(offsetAndMetadata, currentTimestamp, offsetsRetentionMs));
69: 
70:         // 4. Current timestamp - base timestamp < offsets retention => should not expire
71:         currentTimestamp = 999L;
72:         assertFalse(condition.isOffsetExpired(offsetAndMetadata, currentTimestamp, offsetsRetentionMs));
73:     }
74: }
