  @Test
  public void testConsumerGroupHeartbeatEpochTransitionsAcrossCoordinatorFailover() throws ExecutionException, InterruptedException, TimeoutException {
      GroupCoordinatorService service = new GroupCoordinatorServiceBuilder()
          .setConfig(createConfig())
          .setRuntime(mockRuntime())
          .build();

      String groupId = "test-group";
      String memberId = Uuid.randomUuid().toString();

      // Service not started - coordinator unavailable
      ConsumerGroupHeartbeatRequestData request = new ConsumerGroupHeartbeatRequestData()
          .setGroupId(groupId)
          .setMemberId(memberId)
          .setMemberEpoch(0)
          .setRebalanceTimeoutMs(5000)
          .setSubscribedTopicNames(List.of("topic-1"))
          .setTopicPartitions(List.of());

      CompletableFuture<ConsumerGroupHeartbeatResponseData> future1 = service.consumerGroupHeartbeat(
          requestContext(ApiKeys.CONSUMER_GROUP_HEARTBEAT),
          request
      );

      assertEquals(Errors.COORDINATOR_NOT_AVAILABLE.code(), future1.get(5, TimeUnit.SECONDS).errorCode());

      // Start coordinator
      service.start();

      // Member sends heartbeat with epoch 1 (skipped epoch 0 transition)
      request.setMemberEpoch(1);
      CompletableFuture<ConsumerGroupHeartbeatResponseData> future2 = service.consumerGroupHeartbeat(
          requestContext(ApiKeys.CONSUMER_GROUP_HEARTBEAT),
          request
      );

      // Verify the assignment contains this member (not another member)
      ConsumerGroupHeartbeatResponseData response = future2.get(5, TimeUnit.SECONDS);
      assertTrue(response.memberEpoch() >= 1, "Member should have valid epoch after failover");
      assertNotEquals(Errors.FENCED_INSTANCE_ID.code(), response.errorCode());

      service.shutdown();
  }
  ```
